    ,[&](VsetType /*vset_type*/) {
      auto trace_data = std::make_shared<VecUnit::ExeTraceData>();
      trace->data = trace_data;
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        vec_unit_->configure(instr, wid, t, rs1_data, rs2_data, rd_data, trace_data.get());
      }
      rd_write = true;
    },
    [&](VlsType vls_type) {
      switch (vls_type) {
      case VlsType::VL:
      case VlsType::VLS:
      case VlsType::VLX: {
        auto trace_data = std::make_shared<VecUnit::MemTraceData>(num_threads);
        trace->data = trace_data;
        for (uint32_t t = thread_start; t < num_threads; ++t) {
          if (!warp.tmask.test(t))
            continue;
          vec_unit_->load(instr, wid, t, rs1_data, rs2_data, trace_data.get());
        }
        rd_write = true;
      } break;
      case VlsType::VS:
      case VlsType::VSS:
      case VlsType::VSX: {
        auto trace_data = std::make_shared<VecUnit::MemTraceData>(num_threads);
        trace->data = trace_data;
        for (uint32_t t = thread_start; t < num_threads; ++t) {
          if (!warp.tmask.test(t))
            continue;
          vec_unit_->store(instr, wid, t, rs1_data, rs2_data, trace_data.get());
        }
      } break;
      default:
        std::abort();
      }
    },
    [&](VopType /*vop_type*/) {
      auto trace_data = std::make_shared<VecUnit::ExeTraceData>();
      trace->data = trace_data;
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        vec_unit_->execute(instr, wid, t, rs1_data, rd_data, trace_data.get());
      }
      rd_write = true;
    }
  #endif // EXT_V_ENABLE
  #ifdef EXT_TCU_ENABLE
    ,[&](TcuType tcu_type) {
      auto tpuArgs = std::get<IntrTcuArgs>(instrArgs);
      switch (tcu_type) {
      case TcuType::WMMA: {
        auto trace_data = std::make_shared<TensorUnit::ExeTraceData>();
        trace->data = trace_data;
        assert(warp.tmask.count() == num_threads);
        tensor_unit_->wmma(wid, tpuArgs.fmt_s, tpuArgs.fmt_d, tpuArgs.step_m, tpuArgs.step_n, rs1_data, rs2_data, rs3_data, rd_data, trace_data.get());
        rd_write = true;
      } break;
      default:
        std::abort();
      }
    }
  #endif // EXT_TCU_ENABLE
  #ifdef EXT_VEGETA_ENABLE
  ,[&](VegetaLsuType lsu_type) {
    switch (lsu_type) {
    case VegetaLsuType::TILE_LOAD_T: {
      auto trace_data = std::make_shared<SparseUnit::MemTraceData>(num_threads);
      trace->data = trace_data;
      // rs1_data contains the base address
      // DestReg (rd) contains the tile register index
      // Immediate offset is extracted in decode and stored in instruction args
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        sparse_unit_->load(instr, wid, t, rs1_data, trace_data.get());
      }
      rd_write = true;
      break;
    }
    case VegetaLsuType::TILE_LOAD_U: {
      auto trace_data = std::make_shared<SparseUnit::MemTraceData>(num_threads);
      trace->data = trace_data;
      // rs1_data contains the base address
      // DestReg (rd) contains the ureg index (mapped to tile regs in load function)
      // Immediate offset is extracted in decode and stored in instruction args
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        sparse_unit_->load(instr, wid, t, rs1_data, trace_data.get());
      }
      rd_write = true;
      break;
    }
    case VegetaLsuType::TILE_LOAD_V: {
      auto trace_data = std::make_shared<SparseUnit::MemTraceData>(num_threads);
      trace->data = trace_data;
      // rs1_data contains the base address
      // DestReg (rd) contains the vreg index (mapped to tile regs in load function)
      // Immediate offset is extracted in decode and stored in instruction args
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        sparse_unit_->load(instr, wid, t, rs1_data, trace_data.get());
      }
      rd_write = true;
      break;
    }
    case VegetaLsuType::TILE_LOAD_M: {
      auto trace_data = std::make_shared<SparseUnit::MemTraceData>(num_threads);
      trace->data = trace_data;
      // rs1_data contains the base address
      // DestReg (rd) contains the metadata register index
      // Immediate offset is extracted in decode and stored in instruction args
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        sparse_unit_->load(instr, wid, t, rs1_data, trace_data.get());
      }
      rd_write = true;
      break;
    }
    case VegetaLsuType::TILE_STORE_T: {
      auto trace_data = std::make_shared<SparseUnit::MemTraceData>(num_threads);
      trace->data = trace_data;
      // rs1_data contains the base address
      // rs2 (SrcReg[1]) contains the source tile register index
      // Immediate offset is extracted in decode and stored in instruction args
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        sparse_unit_->store(instr, wid, t, rs1_data, trace_data.get());
      }
      break;
    }
    default:
      std::abort();
    }
  },
  [&](VegetaTcuType tcu_type) {
    switch (tcu_type) {
    case VegetaTcuType::TILE_GEMM_T: {
      auto trace_data = std::make_shared<SparseUnit::ExeTraceData>();
      trace->data = trace_data;
      assert(warp.tmask.count() == num_threads);

      // Extract tile register indices from instruction
      uint32_t dst_reg = rdest.idx;
      uint32_t src1_reg = instr.getSrcReg(0).idx;
      uint32_t src2_reg = instr.getSrcReg(1).idx;

      // Dense tile × Dense tile → Tile (T × T → T)
      sparse_unit_->tile_gemm_t(dst_reg, src1_reg, src2_reg);
      rd_write = false;  // Writes to tile registers, not scalar registers
    } break;
    case VegetaTcuType::TILE_GEMM_U: {
      auto trace_data = std::make_shared<SparseUnit::ExeTraceData>();
      trace->data = trace_data;
      assert(warp.tmask.count() == num_threads);

      // Extract tile register indices from instruction
      uint32_t dst_reg = rdest.idx;
      uint32_t src1_reg = instr.getSrcReg(0).idx;
      uint32_t src2_reg = instr.getSrcReg(1).idx;

      // Sparse tile (2:4) × Dense tile → Tile (T × U → T)
      // Metadata assumed to be in corresponding m-register (same index as src1)
      sparse_unit_->tile_gemm_u(dst_reg, src1_reg, src2_reg, src1_reg);
      rd_write = false;
    } break;
    case VegetaTcuType::TILE_GEMM_V: {
      auto trace_data = std::make_shared<SparseUnit::ExeTraceData>();
      trace->data = trace_data;
      assert(warp.tmask.count() == num_threads);

      // Extract tile register indices from instruction
      uint32_t dst_reg = rdest.idx;
      uint32_t src1_reg = instr.getSrcReg(0).idx;
      uint32_t src2_reg = instr.getSrcReg(1).idx;

      // Sparse tile (1:4) × Dense tile → Tile (T × V → T)
      sparse_unit_->tile_gemm_v(dst_reg, src1_reg, src2_reg, src1_reg);
      rd_write = false;
    } break;
    case VegetaTcuType::TILE_GEMM_R: {
      auto trace_data = std::make_shared<SparseUnit::ExeTraceData>();
      trace->data = trace_data;
      assert(warp.tmask.count() == num_threads);

      // Extract tile register indices from instruction
      uint32_t dst_reg = rdest.idx;
      uint32_t src1_reg = instr.getSrcReg(0).idx;
      uint32_t src2_reg = instr.getSrcReg(1).idx;

      // Row-wise sparse tile × Dense tile → Tile (T × U → U)
      sparse_unit_->tile_gemm_r(dst_reg, src1_reg, src2_reg, src1_reg);
      rd_write = false;
    } break;
    case VegetaTcuType::WMMA: {
      auto tpuArgs = std::get<IntrVegetaTcuArgs>(instrArgs);
      auto trace_data = std::make_shared<SparseUnit::ExeTraceData>();
      trace->data = trace_data;
      assert(warp.tmask.count() == num_threads);

      // Get metadata from integer registers a0-a7 (x10-x17) for sparse fragA
      // These contain metadata values loaded by mma_sync into a0-a7
      DTH(3, "WMMA: current regfile values:" << std::hex << std::endl);
      for (uint32_t i = 0; i < 32; ++i) {
        DTN(3, "  x" << std::setfill('0') << std::setw(2) << i << ": 0x" << warp.ireg_file.at(i).at(0) << std::dec << std::endl);
      }
      uint32_t metadata[8] = {0};
      for (uint32_t reg = 0; reg < 8; ++reg) {
        // a0-a7 correspond to x10-x17 in RISC-V
        uint32_t a_reg = 10 + reg;  // a0=10, a1=11, ..., a7=17

        // Get value from integer register a_reg for thread 0 (all threads should have same metadata)
        if (warp.tmask.test(0) && a_reg < warp.ireg_file.size()) {
          metadata[reg] = warp.ireg_file.at(a_reg).at(0);
        }
      }
      DTH(3, "WMMA: metadata values:" << std::hex << std::endl);
      for (uint32_t i = 0; i < 8; ++i) {
        DTN(3, "  a" << std::setfill('0') << std::setw(1) << i << ": 0x" << metadata[i] << std::dec << std::endl);
      }

      // Extract sparsity degree from register t0 (x5)
      uint32_t sparsity_degree = 2; // default to 2:4
      const uint32_t t0_reg = 5; // t0 is x5
      if (warp.tmask.test(0) && t0_reg < warp.ireg_file.size()) {
        sparsity_degree = static_cast<uint32_t>(warp.ireg_file.at(t0_reg).at(0));
        // Validate sparsity degree (should be 1 or 2)
        if (sparsity_degree != 1 && sparsity_degree != 2) {
          std::cerr << "Warning: Invalid sparsity degree " << sparsity_degree << " in register t0 (x5), using default 2" << std::endl;
          sparsity_degree = 2;
        }
      }

      // Create updated args with the extracted sparsity degree
      // Note: The sparsity degree is also used by the hardware instruction via register t0 in mma_sync
      IntrVegetaTcuArgs updated_args{tpuArgs.fmt_s, tpuArgs.fmt_d, tpuArgs.step_m, tpuArgs.step_n, static_cast<uint32_t>(sparsity_degree)};

      // Resize rd_data and rs3_data to accommodate WMMA output (tcM * tcN elements)
      // For sparse WMMA, we need at least tcM * tcN elements
      namespace vt = vortex::sparse;
      using cfg = vt::wmma_config_t<NUM_THREADS>;
      uint32_t wmma_size = cfg::tcM * cfg::tcN;
      if (rd_data.size() < wmma_size) {
        rd_data.resize(wmma_size);
      }
      if (rs3_data.size() < wmma_size) {
        rs3_data.resize(wmma_size);
      }

      sparse_unit_->wmma(wid, updated_args.fmt_s, updated_args.fmt_d, updated_args.step_m, updated_args.step_n, rs1_data, rs2_data, rs3_data, rd_data, trace_data.get(), metadata, updated_args.sparsity_degree);
      rd_write = true;
    } break;
    default:
      std::abort();
    }
  }
  #endif // EXT_VEGETA_ENABLE
  );

  if (rd_write) {
    trace->wb = true;
    switch (rdest.type) {
    case RegType::None:
      break;
    case RegType::Integer:
      if (rdest.idx != 0) {
        DPH(2, "Dest Reg: " << rdest << "={");
        for (uint32_t t = 0; t < num_threads; ++t) {
          if (t) DPN(2, ", ");
          if (!warp.tmask.test(t)) {
            DPN(2, "-");
            continue;
          }
          warp.ireg_file.at(rdest.idx).at(t) = rd_data[t].i;
          DPN(2, "0x" << std::hex << rd_data[t].u << std::dec);
        }
        DPN(2, "}" << std::endl);
      } else {
        // disable writes to x0
        trace->wb = false;
      }
      break;
    case RegType::Float:
      DPH(2, "Dest Reg: " << rdest << "={");
      for (uint32_t t = 0; t < num_threads; ++t) {
        if (t) DPN(2, ", ");
        if (!warp.tmask.test(t)) {
          DPN(2, "-");
          continue;
        }
        warp.freg_file.at(rdest.idx).at(t) = rd_data[t].u64;
        if ((rd_data[t].u64 >> 32) == 0xffffffff) {
          DPN(2, "0x" << std::hex << rd_data[t].u32 << std::dec);
        } else {
          DPN(2, "0x" << std::hex << rd_data[t].u64 << std::dec);
        }
      }
      DPN(2, "}" << std::endl);
      break;
  #ifdef EXT_V_ENABLE
    case RegType::Vector:
      DPH(2, "Dest Reg: " << rdest << "={");
      for (uint32_t t = 0; t < num_threads; ++t) {
        if (t) DPN(2, ", ");
        if (!warp.tmask.test(t)) {
          DPN(2, "-");
          continue;
        }
        DPN(2, vec_unit_->dumpRegister(wid, t, rdest.idx));
      }
      DPN(2, "}" << std::endl);
      break;
  #endif
  #ifdef EXT_VEGETA_ENABLE
    case RegType::Tile:
      DPH(2, "Dest Reg: " << rdest << "= Tile register " << rdest.idx << " (data written to sparse unit register file)");
      DPN(2, std::endl);
      break;
  #endif
    default:
      std::cout << "Unrecognized register write back type: " << rdest.type << std::endl;
      std::abort();
      break;
    }
  }

  warp.PC += 4;

  if (warp.PC != next_pc) {
    DP(3, "*** Next PC=0x" << std::hex << next_pc << std::dec);
    warp.PC = next_pc;
  }

  if (warp.tmask != next_tmask) {
    DP(3, "*** New Tmask=" << next_tmask);
    warp.tmask = next_tmask;
    if (!next_tmask.any()) {
      active_warps_.reset(wid);
    }
  }

  DP(5, "Register state:");
  for (uint32_t i = 0; i < MAX_NUM_REGS; ++i) {
    DPN(5, "  %r" << std::setfill('0') << std::setw(2) << i << ':' << std::hex);
    // Integer register file
    for (uint32_t j = 0; j < arch_.num_threads(); ++j) {
      DPN(5, ' ' << std::setfill('0') << std::setw(XLEN/4) << warp.ireg_file.at(i).at(j) << std::setfill(' ') << ' ');
    }
    DPN(5, '|');
    // Floating point register file
    for (uint32_t j = 0; j < arch_.num_threads(); ++j) {
      DPN(5, ' ' << std::setfill('0') << std::setw(16) << warp.freg_file.at(i).at(j) << std::setfill(' ') << ' ');
    }
    DPN(5, std::dec << std::endl);
  }

  return trace;
}

