	return impl_->perf_stats();
}

void SparseUnit::load(const Instr &instr, uint32_t wid, uint32_t tid, const std::vector<reg_data_t>& rs1_data, MemTraceData* trace_data) {
  impl_->load(instr, wid, tid, rs1_data, trace_data);
