template <typename T>
class TFifo : public SimObject<TFifo<T>> {
public:
  using Type = T;

  TFifo(const SimContext& ctx, const char* name, uint32_t delay, uint32_t capacity = 0)
    : SimObject<TFifo<T>>(ctx, name)
    , bus_(this, capacity)
    , delay_(delay) {
  }

  void reset() {
    //--
  }

  void tick() {
    //--
  }

  bool empty() const {
    return bus_.empty();
  }

  bool full() const {
    return bus_.full();
  }

  uint32_t size() const {
    return bus_.size();
  }

  void push(const Type& value) {
    if (bus_.full()) {
      throw std::runtime_error("FIFO is full");
    }
    bus_.push(value, delay_);
  }

  Type& front() {
    if (bus_.empty()) {
      throw std::runtime_error("FIFO is empty");
    }
    return bus_.front();
  }

  const Type& front() const {
    if (bus_.empty()) {
      throw std::runtime_error("FIFO is empty");
    }
    return bus_.front();
  }

  void pop() {
    if (bus_.empty()) {
      throw std::runtime_error("FIFO is empty");
    }
    bus_.pop();
  }

private:
  SimPort<Type> bus_;
  uint32_t delay_;
};

