  std::cout << std::dec;

  // Print metadata
  std::cout << "\n=== Metadata (" << sparseA.meta.size() << " entries; padded size "
            << meta_size << " bytes) ===" << std::endl;
  size_t meta_idx = 0;
  for (uint32_t m = 0; m < M; ++m) {
    std::cout << "Row " << m << " metadata: ";
    for (uint32_t blk = 0; blk < K / 4; ++blk) {
