  // Print metadata with position interpretation
  std::cout << "\n=== Metadata Interpretation (showing kept positions) ===" << std::endl;
  meta_idx = 0;
  val_idx = 0;
  for (uint32_t m = 0; m < M; ++m) {
    std::cout << "Row " << m << ": ";
    for (uint32_t blk = 0; blk < K / 4; ++blk) {
      uint8_t mask = sparseA.meta[meta_idx++];
