  // cleanup
  std::cout << "cleanup" << std::endl;
  cleanup();

  if (errors != 0) {
    std::cout << "Found " << std::dec << errors << " errors!" << std::endl;
    std::cout << "FAILED!" << std::endl;
    return errors;
  }

  std::cout << "Sparse GEMM completed successfully!" << std::endl;
  std::cout << "PASSED!" << std::endl;

  return 0;
}

